parameters.jsCode:
// Parse Anthropic response: response.content[0].text is JSON string like
// {"category":"groceries","confidence":0.9}
const raw = $input.first().json?.content?.[0]?.text ?? '{}';
let parsed;
try {
  parsed = JSON.parse(raw);
} catch (e) {
  parsed = { category: 'other', confidence: 0 };
}
return [{ json: { category: parsed.category ?? 'other', confidence: parsed.confidence ?? 0 } }];
